{"command": "cd $WORKSPACE_DIR && python3 -c "
from docx import Document
from lxml import etree
d = Document('output/compromise-proposals.docx')
def show(p,label):
    ppr=p._p.find('{http://schemas.openxmlformats.org/wordprocessingml/2006/main}pPr')
    print('===',label,'===')
    if ppr is not None:
        print(etree.tostring(ppr, pretty_print=True).decode()[:500])
    else:
        print('(no pPr)')
# block quote para
for i,p in enumerate(d.paragraphs):
    if p.text.strip().startswith('EXCEPT AS SET FORTH'):
        show(p,'BLOCK QUOTE (clause)'); break
# a normal body para
for i,p in enumerate(d.paragraphs):
    if p.style.name=='Normal' and p.text.strip().startswith('The proposal concedes'):
        show(p,'NORMAL BODY'); break
""}

