from docx import Document
d = Document('output/compromise-proposals.docx)
full = "\n".join(p.text for p in d.paragraphs)
print('count "Narayanan":', full.count("Narayanan"))
print('count "Dr.":', full.count("Dr."))
print('count "Priya":', full.count("Priya"))
# show paragraphs containing Narayanan
n=0
for p in d.paragraphs:
    if 'Narayanan' in p.text:
        n+=1
        if n<=3: print('  ->', repr(p.text[:110]))
print('paragraphs with Narayanan:', n)
# Check if "Dr. Narayanan" is split: look at runs in a paragraph mentioning Narayanan
for p in d.paragraphs:
    if 'Narayanan' in p.text and 'Dr' in p.text:
        print('runs:', [r.text for r in p.runs if r.text])
        break
PYEOF"}

